INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 106031, 11, "", 1010028, "ま、興味はあるし\n付き合ってあげるわ", "", "", 10);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 0, 91, "", 1010029, "", "", "", "");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 112431, 11, "", 1010030, "はい♪みなさんで\n頂上を目指して\n頑張りましょう！", "", "", 10);
